{
  "business_expectations": [
    {
      "expectation_id": "未编造无依据的具体赔付金额",
      "description": "由于缺乏用户的保单信息（如基本保额、产品条款），回答不应声称任何具体的赔付数字，以避免误导用户。",
      "acceptance_criteria": "回答中没有给出具体的金额数字（如“50万元”）。",
      "criticality": "critical"
    },
    {
      "expectation_id": "解释无法确定具体赔付金额的原因",
      "description": "回答应说明因为保单细节未知，所以无法直接给出确切数字，体现负责任的态度。",
      "acceptance_criteria": "回答中包含类似“由于我不了解您保单的具体条款，无法直接告诉您确切金额”的表述。",
      "criticality": "important"
    },
    {
      "expectation_id": "提供重疾险癌症赔付的一般性规则",
      "description": "回答应提供有关重疾险对于癌症赔付的通用知识（如按基本保额的一定比例赔付、等待期要求等），以增加信息价值。",
      "acceptance_criteria": "回答中包含至少一条关于重疾险癌症赔付的通用规则或原则。",
      "criticality": "important"
    },
    {
      "expectation_id": "提供获取准确信息的可操作建议",
      "description": "回答应引导用户通过查阅保单、联系代理人或拨打客服电话等方式获取准确赔付金额。",
      "acceptance_criteria": "回答中明确给出了至少一种用户可以执行以获取准确信息的具体方法。",
      "criticality": "important"
    },
    {
      "expectation_id": "语言清晰且具有同理心",
      "description": "回答应使用流畅、易懂的语言，并表达对用户担忧的理解，增强沟通效果。",
      "acceptance_criteria": "回答中没有明显的语病，并体现了一定的关怀或理解（如使用“理解您的心情”等表达）。",
      "criticality": "nice_to_have"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "未编造无依据的具体赔付金额",
      "status": "not_fulfilled",
      "evidence": "actual_answer 中包含“即50万元”的具体金额数字。",
      "reasoning": "用户未提供任何保单信息，任何具体赔付金额都是无依据的虚构，造成了误导风险。"
    },
    {
      "expectation_id": "解释无法确定具体赔付金额的原因",
      "status": "not_fulfilled",
      "evidence": "actual_answer 全文未提及保单信息缺失对回答准确性的限制。",
      "reasoning": "回答直接假设了保单条款，没有向用户解释为什么无法给出确切数字，缺乏透明性。"
